<script lang="ts">
  import { onMount } from 'svelte';
  import Prose from '../lib/components/Prose.svelte';

  type PartialProduct = { expr: string; stated: string; actual: string; correct: boolean };
  type Trace = {
    digit: number;
    probe: number;
    operands: { a: string; b: string };
    truth: string;
    answer: string | null;
    finalCorrect: boolean;
    partialProducts: PartialProduct[];
    correctSteps: number;
    totalSteps: number;
    pStep: number;
  };
  type Data = { model: string; traces: Trace[] };

  // Cherry-picked representatives: easy / boundary / failing.
  const PICK = [
    { digit: 5, probe: 0, label: 'comfortable' },
    { digit: 10, probe: 1, label: 'at the edge' },
    { digit: 20, probe: 0, label: 'past the edge' },
  ];

  let data = $state<Data | null>(null);

  onMount(async () => {
    const res = await fetch('./mul-traces.json');
    data = await res.json();
  });

  function pick(traces: Trace[], d: number, p: number): Trace | null {
    return traces.find((t) => t.digit === d && t.probe === p) ?? null;
  }

  function formatNumberWithCommas(s: string): string {
    return BigInt(s).toLocaleString('en-US');
  }

  function scientific(n: number): string {
    if (n >= 0.01) return n.toFixed(3);
    if (n === 0) return '0';
    const exp = Math.floor(Math.log10(n));
    const mant = n / Math.pow(10, exp);
    return `${mant.toFixed(2)} × 10^${exp}`;
  }
</script>

<section id="reliability" class="section">
  <Prose>
    <header class="header">
      <div class="eyebrow">Framework</div>
      <h2>Reliability is step accuracy</h2>
    </header>

    <p>
      Every model output is learned recall. The outline of an algorithm — which
      operations happen, in what order, and how data moves between them — is a
      pattern stored in the weights. The operations inside that outline are stored
      the same way: arithmetic facts, lookups, transformations, and state updates.
      At the parameter level, they are all just steps with some probability of
      being emitted correctly.
    </p>

    <p>
      Long multiplication makes the idea concrete. The procedure is everywhere in
      training data, and so are the single-digit facts it depends on. Facts like
      <em>7 × 8 = 56</em> are densely represented. At inference time, the model is
      not deriving a proof of multiplication; it is emitting the pattern training
      made likely.
    </p>
  </Prose>

  <div class="training-origins" aria-label="Algorithm shape and arithmetic operations both come from training">
    <div class="origin-card">
      <div class="origin-label">Both come from training</div>

      <div class="tableau">
